1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	const sortCells = (cells: Cell[]): Cell[] =>
5	  [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
6	
7	describe("Game of Life - nextGeneration", () => {
8	  it("empty input returns empty output", () => {
9	    expect(nextGeneration([])).toEqual([]);
10	  });
11	
12	  it("single live cell dies (0 neighbours) - [(0,0)] -> []", () => {
13	    expect(nextGeneration([[0, 0]])).toEqual([]);
14	  });
15	
16	  it("two adjacent live cells both die (1 neighbour each) - [(0,1),(1,1)] -> []", () => {
17	    expect(
18	      nextGeneration([
19	        [0, 1],
20	        [1, 1],
21	      ]),
22	    ).toEqual([]);
23	  });
24	
25	  it("block is a still life - [(0,0),(1,0),(0,1),(1,1)] unchanged (each live cell has 3 neighbours, no dead cell has 3)", () => {
26	    const block: Cell[] = [
27	      [0, 0],
28	      [1, 0],
29	      [0, 1],
30	      [1, 1],
31	    ];
32	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
33	  });
34	
35	  it("dead cell with exactly 3 live neighbours is born (Rule 4 L-shape) - [(0,2),(1,2),(0,1)] -> [(0,2),(1,2),(0,1),(1,1)]", () => {
36	    const input: Cell[] = [
37	      [0, 2],
38	      [1, 2],
39	      [0, 1],
40	    ];
41	    const expected: Cell[] = [
42	      [0, 2],
43	      [1, 2],
44	      [0, 1],
45	      [1, 1],
46	    ];
47	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
48	  });
49	
50	  it("live cell with 4 neighbours dies, corners born (Rule 3 + shape) - [(1,2),(0,1),(1,1),(2,1),(1,0)] -> [(1,2),(0,1),(2,1),(1,0),(0,0),(2,0),(0,2),(2,2)]", () => {
51	    const input: Cell[] = [
52	      [1, 2],
53	      [0, 1],
54	      [1, 1],
55	      [2, 1],
56	      [1, 0],
57	    ];
58	    const expected: Cell[] = [
59	      [1, 2],
60	      [0, 1],
