1	export type Cell = [number, number];
2	
3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const key = (x: number, y: number) => `${x},${y}`;
5	  const alive = new Set(cells.map(([x, y]) => key(x, y)));
6	  const neighbourCounts = new Map<string, number>();
7	
8	  for (const [x, y] of cells) {
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        const k = key(x + dx, y + dy);
13	        neighbourCounts.set(k, (neighbourCounts.get(k) ?? 0) + 1);
14	      }
15	    }
16	  }
17	
18	  const result: Cell[] = [];
19	  for (const [k, count] of neighbourCounts) {
20	    if (count === 3 || (count === 2 && alive.has(k))) {
21	      const [x, y] = k.split(",").map(Number);
22	      result.push([x, y]);
23	    }
24	  }
25	
26	  return result;
27	}
